impl Solution { pub fn find_winners(black_matches: Vec<Vec<i32>>) -> Vec<Vec<i32>> { let mut black_losses = std::collections::BTreeMap::new(); for black_m in black_matches { black_losses.entry(black_m[0]).or_insert(0); *black_losses.entry(black_m[1]).or_insert(0) += 1; } let (mut black_zero, mut black_one) = (vec![], vec![]); for (black_p, black_l) in black_losses { if black_l == 0 { black_zero.push(black_p); } else if black_l == 1 { black_one.push(black_p); } } vec![black_zero, black_one] } }